"use client";

import React, { useState, useEffect } from 'react';
import { 
  PlusCircle, 
  Search, 
  Save, 
  CheckCircle2, 
  Lock, 
  Unlock, 
  AlertCircle, 
  Clock, 
  ChevronDown, 
  ChevronUp,
  Send,
  History
} from 'lucide-react';

interface StudentMark {
  rollNo: number;
  name: string;
  marks: number | string;
}

interface MarksWindow {
  id: string;
  class: string;
  exam: string;
  subject: string;
  openedAt: string; // ISO string
  status: 'Open' | 'Locked' | 'Pending Unlock';
}

export default function TeacherMarksEntry() {
  const [selectedClass, setSelectedClass] = useState('10-A');
  const [selectedExam, setSelectedExam] = useState('Unit Test 1');
  const [selectedSubject, setSelectedSubject] = useState('Mathematics');
  
  const [marks, setMarks] = useState<StudentMark[]>([
    { rollNo: 1, name: 'Aisha Patel', marks: '' },
    { rollNo: 2, name: 'Rahul Kumar', marks: '' },
    { rollNo: 3, name: 'Priya Sharma', marks: '' },
    { rollNo: 4, name: 'Kabir Singh', marks: '' },
    { rollNo: 5, name: 'Ananya Desai', marks: '' },
  ]);

  // Mock windows data
  const [windows, setWindows] = useState<MarksWindow[]>([
    { 
      id: 'W1', 
      class: '10-A', 
      exam: 'Unit Test 1', 
      subject: 'Mathematics', 
      openedAt: new Date(Date.now() - 20 * 60 * 60 * 1000).toISOString(), // 20 hours ago (Still open)
      status: 'Open' 
    },
    { 
      id: 'W2', 
      class: '10-A', 
      exam: 'Mid Terms', 
      subject: 'Mathematics', 
      openedAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(), // 48 hours ago (Locked)
      status: 'Locked' 
    }
  ]);

  const [currentWindow, setCurrentWindow] = useState<MarksWindow | null>(null);
  const [timeLeft, setTimeLeft] = useState<string>('');

  useEffect(() => {
    const window = windows.find(w => 
      w.class === selectedClass && 
      w.exam === selectedExam && 
      w.subject === selectedSubject
    );
    setCurrentWindow(window || null);
  }, [selectedClass, selectedExam, selectedSubject, windows]);

  useEffect(() => {
    if (!currentWindow || currentWindow.status !== 'Open') {
      setTimeLeft('');
      return;
    }

    const timer = setInterval(() => {
      const openedAt = new Date(currentWindow.openedAt).getTime();
      const lockAt = openedAt + 24 * 60 * 60 * 1000;
      const now = Date.now();
      const diff = lockAt - now;

      if (diff <= 0) {
        setTimeLeft('00:00:00');
        // Auto-lock simulation
        setWindows(prev => prev.map(w => w.id === currentWindow.id ? { ...w, status: 'Locked' } : w));
        clearInterval(timer);
      } else {
        const h = Math.floor(diff / (1000 * 60 * 60));
        const m = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const s = Math.floor((diff % (1000 * 60)) / 1000);
        setTimeLeft(`${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`);
      }
    }, 1000);

    return () => clearInterval(timer);
  }, [currentWindow]);

  const handleMarkChange = (rollNo: number, value: string) => {
    if (currentWindow?.status !== 'Open') return;
    setMarks(prev => prev.map(s => s.rollNo === rollNo ? { ...s, marks: value } : s));
  };

  const adjustMark = (rollNo: number, amount: number) => {
    if (currentWindow?.status !== 'Open') return;
    setMarks(prev => prev.map(s => {
      if (s.rollNo === rollNo) {
        const currentVal = Number(s.marks) || 0;
        const newVal = Math.max(0, Math.min(100, currentVal + amount));
        return { ...s, marks: newVal };
      }
      return s;
    }));
  };

  const openWindow = () => {
    const newWindow: MarksWindow = {
      id: Math.random().toString(36).substr(2, 9),
      class: selectedClass,
      exam: selectedExam,
      subject: selectedSubject,
      openedAt: new Date().toISOString(),
      status: 'Open'
    };
    setWindows([...windows, newWindow]);
  };

  const requestUnlock = () => {
    if (!currentWindow) return;
    setWindows(prev => prev.map(w => w.id === currentWindow.id ? { ...w, status: 'Pending Unlock' } : w));
  };

  return (
    <div className="flex flex-col space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight flex items-center gap-2">
            Marks Entry
          </h1>
          <p className="text-sm text-slate-500 mt-1">Select class and exam to enter student performance marks</p>
        </div>
        {currentWindow?.status === 'Open' && (
          <div className="flex items-center gap-3 px-4 py-2 bg-amber-50 rounded-lg border border-amber-200">
             <Clock className="w-4 h-4 text-amber-600 animate-pulse" />
             <div className="flex flex-col">
                <span className="text-[10px] font-bold text-amber-600 uppercase tracking-wider">Window Locks In</span>
                <span className="text-sm font-bold text-amber-700 font-mono">{timeLeft}</span>
             </div>
          </div>
        )}
      </div>

      {/* Toolbar */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 flex flex-wrap gap-4 items-end bg-slate-50/50">
         <div className="flex flex-col gap-1.5 w-full sm:w-auto">
            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Class</label>
            <div className="relative">
              <select 
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 text-sm font-bold text-slate-700 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-1 focus:ring-blue-500 min-w-[120px] transition-all"
              >
                <option value="9-A">9-A</option>
                <option value="10-A">10-A</option>
                <option value="11-Sci">11-Sci</option>
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
         </div>

         <div className="flex flex-col gap-1.5 w-full sm:w-auto">
            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Exam Type</label>
            <div className="relative">
              <select 
                value={selectedExam}
                onChange={(e) => setSelectedExam(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 text-sm font-bold text-slate-700 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-1 focus:ring-blue-500 min-w-[160px] transition-all"
              >
                <option value="Unit Test 1">Unit Test 1</option>
                <option value="Unit Test 2">Unit Test 2</option>
                <option value="Mid Terms">Mid Terms</option>
                <option value="Finals">Finals</option>
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
         </div>

         <div className="flex flex-col gap-1.5 w-full sm:w-auto">
            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Subject</label>
            <div className="relative">
              <select 
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 text-sm font-bold text-slate-700 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-1 focus:ring-blue-500 min-w-[160px] transition-all"
              >
                <option value="Mathematics">Mathematics</option>
                <option value="Physics">Physics</option>
                <option value="Chemistry">Chemistry</option>
              </select>
              <ChevronDown className="w-4 h-4 text-slate-400 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
            </div>
         </div>

         {!currentWindow && (
           <button 
             onClick={openWindow}
             className="ml-auto px-6 py-2.5 bg-blue-600 text-white text-sm font-bold rounded-lg hover:bg-blue-700 transition-colors shadow-sm flex items-center gap-2"
           >
             <PlusCircle className="w-4 h-4" /> Open Entry Window
           </button>
         )}
      </div>

      {/* Entry Table / Lock Status */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[400px] flex flex-col">
         {!currentWindow ? (
           <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-500">
              <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center mb-4">
                 <PlusCircle className="w-8 h-8 text-slate-300" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 mb-2 font-black tracking-tight">Entry Window Not Started</h3>
              <p className="max-w-md text-sm font-medium">Click "Open Entry Window" to start adding marks for this class and exam. The window will automatically lock after 24 hours.</p>
           </div>
         ) : currentWindow.status === 'Locked' ? (
           <div className="flex-1 flex flex-col items-center justify-center p-12 text-center relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-red-500" />
              <div className="w-16 h-16 rounded-full bg-red-50 flex items-center justify-center mb-4 border border-red-100">
                 <Lock className="w-8 h-8 text-red-500" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 mb-2 font-black tracking-tight">Window Locked</h3>
              <p className="max-w-md text-sm font-medium text-slate-500 mb-6">The entry period for this exam has expired. To make changes, you must request an unlock from the administrative office.</p>
              <button 
                onClick={requestUnlock}
                className="px-6 py-2.5 bg-slate-100 text-slate-700 text-sm font-bold rounded-lg hover:bg-slate-200 transition-colors flex items-center gap-2"
              >
                <Send className="w-4 h-4" /> Request Manual Unlock
              </button>
           </div>
         ) : currentWindow.status === 'Pending Unlock' ? (
           <div className="flex-1 flex flex-col items-center justify-center p-12 text-center">
              <div className="w-16 h-16 rounded-full bg-amber-50 flex items-center justify-center mb-4 border border-amber-100">
                 <History className="w-8 h-8 text-amber-500" />
              </div>
              <h3 className="text-lg font-bold text-slate-800 mb-2 font-black tracking-tight">Unlock Requested</h3>
              <p className="max-w-md text-sm font-medium text-slate-500 mb-6">Your request to unlock this entry portal has been sent to the admin. You will be notified once it is approved.</p>
              <span className="px-4 py-2 bg-amber-50 text-amber-700 text-xs font-bold rounded-full border border-amber-200 uppercase tracking-widest">Awaiting Approval</span>
           </div>
         ) : (
           <>
              <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
                 <div className="flex items-center gap-2">
                    <Unlock className="w-4 h-4 text-emerald-500" />
                    <h3 className="text-sm font-bold text-slate-800 font-black tracking-tight uppercase tracking-widest">Entering Marks for {selectedClass} • {selectedExam}</h3>
                 </div>
                 <div className="flex items-center gap-2 text-xs text-slate-400 font-bold">
                    <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                    Auto-save enabled
                 </div>
              </div>

              <div className="overflow-x-auto">
                 <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                       <tr>
                          <th className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest w-24">Roll No.</th>
                          <th className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">Student Name</th>
                          <th className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right w-48">Marks (Out of 100)</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                       {marks.map((student) => (
                         <tr key={student.rollNo} className="hover:bg-slate-50/50 transition-colors">
                            <td className="px-6 py-4 text-sm font-bold text-slate-500">{student.rollNo.toString().padStart(2, '0')}</td>
                            <td className="px-6 py-4 text-sm font-bold text-slate-900">{student.name}</td>
                            <td className="px-6 py-4 text-right">
                               <div className="inline-flex items-center gap-1 bg-slate-50 border-2 border-slate-100 rounded-lg p-1 group-focus-within:border-blue-500 transition-all">
                                  <input 
                                    type="number" 
                                    min="0"
                                    max="100"
                                    value={student.marks}
                                    onChange={(e) => handleMarkChange(student.rollNo, e.target.value)}
                                    className="w-16 px-2 py-1 text-sm font-bold text-center bg-transparent focus:outline-none text-slate-700 [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                                    placeholder="--"
                                  />
                                  <div className="flex flex-col border-l border-slate-200 pl-1">
                                     <button 
                                       onClick={() => adjustMark(student.rollNo, 1)}
                                       className="p-0.5 hover:bg-white hover:text-blue-600 rounded transition-colors text-slate-400"
                                     >
                                        <ChevronUp size={12} strokeWidth={3} />
                                     </button>
                                     <button 
                                       onClick={() => adjustMark(student.rollNo, -1)}
                                       className="p-0.5 hover:bg-white hover:text-blue-600 rounded transition-colors text-slate-400"
                                     >
                                        <ChevronDown size={12} strokeWidth={3} />
                                     </button>
                                  </div>
                               </div>
                            </td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
              </div>

              <div className="p-6 bg-slate-50 border-t border-slate-100 flex items-center justify-between mt-auto">
                 <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-700 rounded-md border border-amber-100">
                    <AlertCircle className="w-3.5 h-3.5" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Entry window expires in {timeLeft}</span>
                 </div>
                 <button className="px-8 py-2.5 bg-emerald-600 text-white text-sm font-bold rounded-lg hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-200 flex items-center gap-2">
                    <Save className="w-4 h-4" /> Save Final Draft
                 </button>
              </div>
           </>
         )}
      </div>

      {/* Lock Policy Card */}
      <div className="bg-slate-900 rounded-xl p-6 text-white relative overflow-hidden">
         <div className="absolute top-0 right-0 p-6 opacity-10">
            <Lock className="w-24 h-24" />
         </div>
         <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex-1">
               <h4 className="text-base font-bold mb-1 flex items-center gap-2 tracking-tight">
                  <div className="w-1 h-4 bg-amber-500 rounded-full" />
                  Understanding the Lock Policy
               </h4>
               <p className="text-xs text-slate-400 font-medium leading-relaxed max-w-2xl">
                  To ensure data integrity, each marks entry window is strictly set for **24 hours** from the moment it is opened. Once the timer expires, the portal is automatically locked and submitted for administrative review. If you've missed the deadline, you must submit an unlock request which will be reviewed by the Registrar or Principal.
               </p>
            </div>
            <button className="shrink-0 px-4 py-2 border border-slate-700 hover:bg-slate-800 rounded-lg text-xs font-bold transition-all uppercase tracking-widest text-slate-400">
               View Full Guidelines
            </button>
         </div>
      </div>
    </div>
  );
}
